        }

        .accordeon .cover--sl__input {
            color: #000;
            font-size: 17px;
            line-height: 26px;
            letter-spacing: 1px;
            position: relative;
            overflow: hidden;
            max-height: 800px;
            padding-bottom: 0px;
            opacity: 1;
            transform: translate(0, 0);
            margin-top: 14px;
            z-index: 2;
        }

        .accordeon .anim {
            padding-top: 10px;
        }

        .accordeon .anim i {
            position: absolute;
            margin-top: 8px;
            left: 225px;
        }

        .accordeon .anim i:before,
        .accordeon .anim i:after {
            content: "";
            position: absolute;
            background-color: #4e4e4e;
            width: 3px;
            height: 9px;
        }

        .accordeon .anim i:before {
            transform: translate(-2px, 0) rotate(45deg);
        }

        .accordeon .anim i:after {
            transform: translate(2px, 0) rotate(-45deg);
        }

        .accordeon .anim input[type="checkbox"] {
            position: absolute;
            cursor: pointer;
            width: 100%;
            z-index: 1;
            opacity: 0;
        }

        .accordeon .anim input[type="checkbox"]:checked~form .cover--sl__input {
            margin-top: 0;
            max-height: 0;
            opacity: 0;
            transform: translate(0, 50%);
            padding-bottom: 0px;
        }

        .accordeon .anim input[type="checkbox"]:checked~i:before {
            transform: translate(2px, 0) rotate(45deg);
        }

        .accordeon .anim input[type="checkbox"]:checked~i:after {
            transform: translate(-2px, 0) rotate(-45deg);
        }

        @keyframes flipdown {
            0% {
                opacity: 0;
                transform-origin: top center;
                transform: rotateX(-90deg);
            }

            5% {
                opacity: 1;
            }

            80% {
                transform: rotateX(8deg);
            }

            83% {
                transform: rotateX(6deg);
            }

            92% {
                transform: rotateX(-3deg);
            }

            100% {
                transform-origin: top center;
                transform: rotateX(0deg);
            }
        }

