        .slider {
            position: absolute;
            width: 91px;
            cursor: pointer;
            top: 0;
            left: 50%;
            right: 0;
            bottom: 0;
            background-color: #fff;
            transition: 0.4s;
            box-shadow: inset -2px 2px 5px 0px rgba(0, 0, 0, 0.2);
            transform: translateX(-55%);
        }

        .slider:before {
            position: absolute;
            content: "";
            height: 26px;
            width: 26px;
            left: 6px;
            bottom: 6px;
            background-color: #0091db;
            transition: 0.4s;
        }

        input:checked+.slider:before {
            transform: translateX(52px);
        }

        .slider.round {
            border-radius: 34px;
        }

        .slider.round:before {
            border-radius: 50%;
        }

