        .card-slider {
            position: relative;
        }

        .card-slider:before,
        .card-slider:after {
            content: " ";
            display: table;
        }

        .card-slider:after {
            clear: both;
        }

        .card-slider li {
            margin-bottom: 2rem;
        }

        .card-slider__title {
            margin: 0 10px 0 2px;
            text-transform: uppercase;
            font-size: 1.8rem;
            font-weight: 400;
            background: #24315e;
            color: #fff;
            padding: 6px;
            width: 100%;
        }

        .card-slider__subtitle {
            font-size: 1.5rem;
        }

        .card-slider__subsubtitle {
            font-size: 1.5rem;
            margin-left: 10px;
        }

        .card-slider .slick-list {
            padding: 10px 32px 10px 0;
            overflow: visible;
        }

        .card-slider .slick-slide {
            margin: 0;
        }

        .card-slider .slick-arrow {
            display: none !important;
        }

        .card-slider.slider_HD {
            background-color: #fff;
        }

        .card-slider .slick-dots,
        .home-carousel .slick-dots,
        .settlementsApp__cards .slick-dots {
            visibility: hidden;
            display: none !important;
            margin: 0;
            padding: 0;
            text-align: center;
        }

        .card-slider .slick-dots li,
        .home-carousel .slick-dots li,
        .settlementsApp__cards .slick-dots li {
            display: inline-block;
            width: 14px;
            height: 14px;
            margin: 0 5px;
            padding: 0;
            border: 1px solid #83898b;
            border-radius: 50%;
            background: #fff;
            text-indent: -999px;
            overflow: hidden;
            cursor: pointer;
            transition: all 0.2s;
        }

        .card-slider .slick-dots li:hover,
        .card-slider .slick-dots li:focus,
        .home-carousel .slick-dots li:hover,
        .home-carousel .slick-dots li:focus,
        .settlementsApp__cards .slick-dots li:hover,
        .settlementsApp__cards .slick-dots li:focus {
            border-color: #0091db;
        }

        .card-slider .slick-dots li.slick-active,
        .home-carousel .slick-dots li.slick-active,
        .settlementsApp__cards .slick-dots li.slick-active {
            border-color: #0091db;
            background: #0091db;
        }

        .home-carousel .slick-prev {
            left: 50%;
            margin-left: -65px;
        }

        .home-carousel .slick-prev:before {
            right: 0;
            border-width: 10px 10px 10px 0;
            border-color: transparent #f1f1f1 transparent transparent;
        }

        .home-carousel .slick-prev:after {
            right: 2px;
            border-width: 10px 10px 10px 0;
            border-color: transparent #dfdfdf transparent transparent;
        }

        .home-carousel .slick-prev:hover:after,
        .home-carousel .slick-prev:focus:after {
            border-color: transparent #0091db transparent transparent;
        }

        .home-carousel .slick-next {
            right: 50%;
            margin-right: -65px;
        }

        .home-carousel .slick-next:before {
            left: 0;
            border-width: 10px 0 10px 10px;
            border-color: transparent transparent transparent #f1f1f1;
        }

        .home-carousel .slick-next:after {
            left: 2px;
            border-width: 10px 0 10px 10px;
            border-color: transparent transparent transparent #dfdfdf;
        }

        .home-carousel .slick-next:hover:after,
        .home-carousel .slick-next:focus:after {
            border-color: transparent transparent transparent #0091db;
        }

        @media only screen and (min-width: 768px) {

            .card-slider__title,
            .card-slider__subtitle,
            .card-slider__subsubtitle {
                display: none;
            }

            .card-slider .slick-track {
                margin-left: 0;
            }

            .card-slider .slick-list {
                padding: 0;
                overflow: visible;
            }

            .card-slider .slick-slide {
                margin: 0;
            }

            .card-slider.slider_HD {
                background-color: #fff;
            }

            .card-slider .slick-arrow {
                position: absolute;
                bottom: 3px;
                width: 12px;
                height: 20px;
                padding: 0;
                text-indent: -999px;
                overflow: hidden;
                border: none;
                background: none;
            }

            .card-slider .slick-arrow:hover,
            .card-slider .slick-arrow:focus {
                box-shadow: none;
                outline: none;
            }

            .card-slider .slick-arrow:before {
                z-index: 1;
            }

            .card-slider .slick-arrow:after {
                z-index: 0;
            }

            .card-slider .slick-arrow:before,
            .card-slider .slick-arrow:after {
                position: absolute;
                top: 0;
                content: "";
                width: 0;
                height: 0;
                border-style: solid;
                transition: all 0.3s;
            }

            .card-slider .slick-arrow.slick-disabled {
                opacity: 0;
            }

            .tab-pane .card-slider .slick-list {
                margin-left: 50px;
                overflow: hidden;
                padding-bottom: 2rem;
            }

            .card-slider .slick-prev {
                left: 50%;
                margin-left: -65px;
            }

            .card-slider .slick-prev:before {
                right: 0;
                border-width: 10px 10px 10px 0;
                border-color: transparent #f1f1f1 transparent transparent;
            }

            .card-slider .slick-prev:after {
                right: 2px;
                border-width: 10px 10px 10px 0;
                border-color: transparent #dfdfdf transparent transparent;
            }

            .card-slider .slick-prev:hover:after,
            .card-slider .slick-prev:focus:after {
                border-color: transparent #0091db transparent transparent;
            }

            .card-slider .slick-next {
                right: 50%;
                margin-right: -65px;
            }

            .card-slider .slick-next:before {
                left: 0;
                border-width: 10px 0 10px 10px;
                border-color: transparent transparent transparent #f1f1f1;
            }

            .card-slider .slick-next:after {
                left: 2px;
                border-width: 10px 0 10px 10px;
                border-color: transparent transparent transparent #dfdfdf;
            }

            .card-slider .slick-next:hover:after,
            .card-slider .slick-next:focus:after {
                border-color: transparent transparent transparent #0091db;
            }
        }

        @media only screen and (min-width: 992px) {
            .card-slider {
                overflow: hidden;
            }

            .card-slider__title {
                background: none;
                color: inherit;
                padding: 2rem 0;
                width: auto;
            }
        }

