        .wrapper-cover {
            position: relative;
        }

        .cover {
            position: relative;
            overflow: hidden;
        }

        .cover .container {
            padding: 0 !important;
        }

        .cover__angle {
            position: absolute;
            height: 40px;
            width: 100%;
        }

        .cover__angle::before,
        .cover__angle::after {
            content: "";
            position: absolute;
            top: 0;
        }

        .cover__angle::before {
            width: calc(100% - 40px);
            height: 100%;
        }

        .cover__angle::after {
            top: 20px;
            right: -20px;
            height: 0;
            width: 0;
            transform: rotate(45deg);
            border: 20px solid transparent;
        }

        .cover__angle--top {
            top: -40px;
            display: none;
        }

        .cover__angle--top::before {
            left: 40px;
        }

        .cover__angle--top::after {
            top: 0;
            right: 100%;
            margin-right: -40px;
            border-left: 20px solid transparent;
            border-top: 20px solid transparent;
        }

        .cover__angle--bottom {
            bottom: 0;
            display: block;
        }

        .cover__angle--bottom::before {
            right: 40px;
        }

        .cover__angle--bottom::after {
            margin-left: -40px;
            border-right: 20px solid transparent;
            border-bottom: 20px solid transparent;
            background-image:
                /*savepage-url=/medias/images/icones/ico-pattern-dot.png*/
                url();
            background-color: #fff;
        }

