        .shortcut {
            display: block;
            margin: 0 auto 30px;
            max-width: 350px;
            border: 1px solid #fff;
            border-radius: 10px;
            background-color: #0091db;
            color: #fff !important;
            text-decoration: none !important;
            transition: all 0.2s ease-in-out;
            cursor: pointer;
        }

        .shortcut__inner {
            padding: 1.6rem 3rem 2rem;
            text-align: center;
        }

        .shortcut__title {
            margin: 0 0 1.4rem;
            font-weight: 300;
            font-size: 1.8rem;
            letter-spacing: 0.05em;
            transition: color 0.2s ease-in-out;
        }

        .shortcut__icon {
            position: relative;
            margin: 0 0 2rem;
        }

        .shortcut__icon img {
            display: block;
            margin: 0 auto;
            transition: all 0.2s ease-in-out;
        }

        .shortcut__icon .default {
            opacity: 1;
        }

        .shortcut__icon .hover {
            position: absolute;
            top: 0;
            left: 50%;
            transform: translateX(-50%);
            opacity: 0;
        }

        .shortcut__text {
            margin: 0 0 1.4rem;
            font-weight: 300;
            font-size: 1.6rem;
            line-height: 115%;
            letter-spacing: 0.05em;
            transition: color 0.2s ease-in-out;
        }

        .shortcut__footer {
            text-align: center;
            position: relative;
            padding-left: 20px;
            margin-top: 20px;
        }

        .shortcut__footer span {
            display: inline-block;
            font-weight: 400;
            color: #fff !important;
            text-decoration: none !important;
            position: relative;
        }

        .shortcut__footer span::before {
            content: "";
            display: block;
            width: 15px;
            height: 2px;
            background-color: #0091db;
            position: absolute;
            left: -20px;
            top: 12px;
            z-index: 5;
        }

        .shortcut__footer span::before {
            background-color: #fff;
        }

        .shortcut__footer span:hover,
        .shortcut__footer span:active {
            text-decoration: underline !important;
        }

        .shortcut:hover,
        .shortcut:focus {
            border-color: #0091db;
        }

        .shortcut:hover .shortcut__icon .default,
        .shortcut:focus .shortcut__icon .default {
            opacity: 0;
        }

        .shortcut:hover .shortcut__icon .hover,
        .shortcut:focus .shortcut__icon .hover {
            opacity: 1;
        }

        .shortcut:hover .shortcut__footer span,
        .shortcut:focus .shortcut__footer span {
            text-decoration: underline !important;
        }

        .shortcut--blockClick {
            cursor: pointer;
        }

        .shortcut--blockClick:hover .shortcut__title,
        .shortcut--blockClick:hover .shortcut__text,
        .shortcut--blockClick:focus .shortcut__title,
        .shortcut--blockClick:focus .shortcut__text {
            color: #0091db;
        }

        .shortcut--blockClick:hover .link-round,
        .shortcut--blockClick:focus .link-round {
