                box-shadow: 0 0 25px 10px rgba(0, 0, 0, 0.3);
                transform: translateX(-50%);
            }

            .historybred {
                padding-bottom: 2rem;
            }

            .historybred__col--1 {
                margin-bottom: 0;
                text-align: right;
            }

            .historybred__col--1 .historybred__pic {
                float: right;
                max-width: inherit;
                margin-right: 0;
                margin-left: 3rem;
            }

            .historybred__col--1 .historybred__pic:first-child {
                display: none;
            }

            .historybred__col--3 {
                display: block;
                text-align: left;
            }

            .historybred__col--3 .historybred__pic {
                float: left;
                margin-right: 3rem;
            }

            .historybred__col--3 .historybred__pic:last-child {
                display: none;
            }

            .historybred__action .link-round {
                min-width: 213px;
            }
        }

        @media only screen and (min-width: 992px) {
            .historybred {
                padding-top: 4.1rem;
                padding-bottom: 4.2rem;
            }

            .historybred__title {
                margin-bottom: 3rem;
            }
        }

        @media only screen and (min-width: 1140px) {

            .historybred .historybred__col:before,
            .historybred .historybred__col:after {
                content: " ";
                display: table;
            }

            .historybred .historybred__col:after {
                clear: both;
            }

            .historybred .historybred__col--1 .historybred__pic {
                max-width: calc(50% - 3rem);
                float: right;
            }

            .historybred .historybred__col--1 .historybred__pic:first-child {
                display: block;
            }

            .historybred .historybred__col--3 .historybred__pic {
                max-width: calc(50% - 3rem);
                float: left;
            }

            .historybred .historybred__col--3 .historybred__pic:last-child {
                display: block;
            }

            .historybred__title {
                margin-bottom: 3rem;
            }
        }

        @media print {
            * {
                color: #000 !important;
            }

            body,
            body.stick-header {
                padding-top: 0 !important;
            }

            .color-white,
            .link-trait {
                color: #000 !important;
            }

            .main-logo {
                float: none !important;
                margin: 0 auto !important;
            }

            .wrapper-header {
                position: static !important;
                height: auto !important;
                top: inherit !important;
                right: inherit !important;
                bottom: inherit !important;
                left: inherit !important;
