            }

            .news-card,
            .otherCard {
                max-width: 200px !important;
            }

            .news-card,
            .gammeCard,
            .otherCard {
                display: inline-block !important;
            }

            .simpleCard {
                margin-right: auto !important;
                margin-left: auto !important;
            }

            .bg-color-grey-1 {
                background: transparent !important;
            }

            .bg-color-grey-2 {
                background: transparent !important;
            }

            .bg-color-grey-3 {
                background: transparent !important;
            }

            .bg-color-grey-4 {
                background: transparent !important;
            }

            .bg-color-grey-5 {
                background: transparent !important;
            }

            .bg-color-grey-6 {
                background: transparent !important;
            }

            .bg-color-grey-7 {
                background: transparent !important;
            }

            .bg-color-grey-8 {
                background: transparent !important;
            }

            .section--news,
            .card-slider,
            .slick-track {
                width: 100% !important;
                transform: none !important;
                text-align: center !important;
                vertical-align: top !important;
            }

            .section--news [class^="col-"],
            .card-slider [class^="col-"],
            .slick-track [class^="col-"] {
                display: inline-block !important;
                width: auto !important;
                float: none !important;
            }

            .slick-slide,
            .slick-slide>div {
                display: inline-block !important;
                width: auto !important;
                vertical-align: top !important;
            }

            .slick-slide {
                max-width: 33.33% !important;
            }

            .card-slider,
            .slick-slide {
                float: none !important;
                text-align: center !important;
            }

            .card-slider li,
            .slick-slide li {
                display: inline-block !important;
                margin-left: 0 !important;
                padding-left: 0 !important;
                width: auto !important;
            }

            .exergue {
                margin-top: 20pt;
            }

            .section-values__col .base-title {
                padding-top: 0 !important;
                height: auto !important;
            }

            .toggle-slide {
                display: block !important;
            }

            .news-card--exergue .news-card__img::after,
            .news-card--nopic {
                background: #fff !important;
            }

            .nav-tabs--sitemap .nav-item.active .nav-link,
            .nav-tabs--sitemap .nav-item.active .nav-link .nav-link__inner {
                color: #fff !important;
            }

            .home-carousel .cover__content {
